278	// Route creates a new Mux and mounts it along the `pattern` as a subrouter.
279	// Effectively, this is a short-hand call to Mount. See _examples/.
280	func (mx *Mux) Route(pattern string, fn func(r Router)) Router {
281		if fn == nil {
282			panic(fmt.Sprintf("chi: attempting to Route() a nil subrouter on '%s'", pattern))
283		}
284		subRouter := NewRouter()
285		fn(subRouter)
286		mx.Mount(pattern, subRouter)
287		return subRouter
288	}
289	
290	// Mount attaches another http.Handler or chi Router as a subrouter along a routing
291	// path. It's very useful to split up a large API as many independent routers and
292	// compose them as a single service using Mount. See _examples/.
293	//
294	// Note that Mount() simply sets a wildcard along the `pattern` that will continue
295	// routing at the `handler`, which in most cases is another chi.Router. As a result,
296	// if you define two Mount() routes on the exact same pattern the mount will panic.
297	func (mx *Mux) Mount(pattern string, handler http.Handler) {
298		if handler == nil {
299			panic(fmt.Sprintf("chi: attempting to Mount() a nil handler on '%s'", pattern))
300		}
301	
302		// Provide runtime safety for ensuring a pattern isn't mounted on an existing
303		// routing pattern.
304		if mx.tree.findPattern(pattern+"*") || mx.tree.findPattern(pattern+"/*") {
305			panic(fmt.Sprintf("chi: attempting to Mount() a handler on an existing path, '%s'", pattern))
306		}
307	
308		// Assign sub-Router's with the parent not found & method not allowed handler if not specified.
309		subr, ok := handler.(*Mux)
310		if ok && subr.notFoundHandler == nil && mx.notFoundHandler != nil {
311			subr.NotFound(mx.notFoundHandler)
312		}
313		if ok && subr.methodNotAllowedHandler == nil && mx.methodNotAllowedHandler != nil {
314			subr.MethodNotAllowed(mx.methodNotAllowedHandler)
315		}
316	
317		mountHandler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
318			rctx := RouteContext(r.Context())
319	
320			// shift the url path past the previous subrouter
321			rctx.RoutePath = mx.nextRoutePath(rctx)
322	
323			// reset the wildcard URLParam which connects the subrouter
324			n := len(rctx.URLParams.Keys) - 1
325			if n >= 0 && rctx.URLParams.Keys[n] == "*" && len(rctx.URLParams.Values) > n {
326				rctx.URLParams.Values[n] = ""
327			}
328	
329			handler.ServeHTTP(w, r)
330		})
331	
332		if pattern == "" || pattern[len(pattern)-1] != '/' {
333			mx.handle(mALL|mSTUB, pattern, mountHandler)
334			mx.handle(mALL|mSTUB, pattern+"/", mountHandler)
335			pattern += "/"
336		}
337	
338		method := mALL
339		subroutes, _ := handler.(Routes)
340		if subroutes != nil {
341			method |= mSTUB
342		}
343		n := mx.handle(method, pattern+"*", mountHandler)
344	
345		if subroutes != nil {
346			n.subroutes = subroutes
347		}
348	}
