350	// Routes returns a slice of routing information from the tree,
351	// useful for traversing available routes of a router.
352	func (mx *Mux) Routes() []Route {
353		return mx.tree.routes()
354	}
355	
356	// Middlewares returns a slice of middleware handler functions.
357	func (mx *Mux) Middlewares() Middlewares {
358		return mx.middlewares
359	}
360	
361	// Match searches the routing tree for a handler that matches the method/path.
362	// It's similar to routing a http request, but without executing the handler
363	// thereafter.
364	//
365	// Note: the *Context state is updated during execution, so manage
366	// the state carefully or make a NewRouteContext().
367	func (mx *Mux) Match(rctx *Context, method, path string) bool {
368		m, ok := methodMap[method]
369		if !ok {
370			return false
371		}
372	
373		node, _, h := mx.tree.FindRoute(rctx, m, path)
374	
375		if node != nil && node.subroutes != nil {
376			rctx.RoutePath = mx.nextRoutePath(rctx)
377			return node.subroutes.Match(rctx, method, rctx.RoutePath)
378		}
379	
380		return h != nil
381	}
382	
383	// NotFoundHandler returns the default Mux 404 responder whenever a route
384	// cannot be found.
385	func (mx *Mux) NotFoundHandler() http.HandlerFunc {
386		if mx.notFoundHandler != nil {
387			return mx.notFoundHandler
388		}
389		return http.NotFound
390	}
391	
392	// MethodNotAllowedHandler returns the default Mux 405 responder whenever
393	// a method cannot be resolved for a route.
394	func (mx *Mux) MethodNotAllowedHandler(methodsAllowed ...methodTyp) http.HandlerFunc {
395		if mx.methodNotAllowedHandler != nil {
396			return mx.methodNotAllowedHandler
397		}
398		return methodNotAllowedHandler(methodsAllowed...)
399	}
400	
401	// handle registers a http.Handler in the routing tree for a particular http method
402	// and routing pattern.
403	func (mx *Mux) handle(method methodTyp, pattern string, handler http.Handler) *node {
404		if len(pattern) == 0 || pattern[0] != '/' {
405			panic(fmt.Sprintf("chi: routing pattern must begin with '/' in '%s'", pattern))
406		}
407	
408		// Build the computed routing handler for this routing pattern.
409		if !mx.inline && mx.handler == nil {
410			mx.updateRouteHandler()
411		}
412	
413		// Build endpoint handler with inline middlewares for the route
414		var h http.Handler
415		if mx.inline {
416			mx.handler = http.HandlerFunc(mx.routeHTTP)
417			h = Chain(mx.middlewares...).Handler(handler)
418		} else {
419			h = handler
420		}
421	
422		// Add the endpoint to the tree and return the node
423		return mx.tree.InsertRoute(method, pattern, h)
424	}
425	
426	// routeHTTP routes a http.Request through the Mux routing tree to serve
427	// the matching handler for a particular http method.
428	func (mx *Mux) routeHTTP(w http.ResponseWriter, r *http.Request) {
429		// Grab the route context object
430		rctx := r.Context().Value(RouteCtxKey).(*Context)
431	
432		// The request routing path
433		routePath := rctx.RoutePath
434		if routePath == "" {
435			if r.URL.RawPath != "" {
436				routePath = r.URL.RawPath
437			} else {
438				routePath = r.URL.Path
439			}
440			if routePath == "" {
441				routePath = "/"
442			}
443		}
444	
445		// Check if method is supported by chi
446		if rctx.RouteMethod == "" {
447			rctx.RouteMethod = r.Method
448		}
449		method, ok := methodMap[rctx.RouteMethod]
450		if !ok {
451			mx.MethodNotAllowedHandler().ServeHTTP(w, r)
452			return
453		}
454	
455		// Find the route
456		if _, _, h := mx.tree.FindRoute(rctx, method, routePath); h != nil {
457			h.ServeHTTP(w, r)
458			return
459		}
460		if rctx.methodNotAllowed {
461			mx.MethodNotAllowedHandler(rctx.methodsAllowed...).ServeHTTP(w, r)
462		} else {
463			mx.NotFoundHandler().ServeHTTP(w, r)
464		}
465	}
466	
467	func (mx *Mux) nextRoutePath(rctx *Context) string {
468		routePath := "/"
469		nx := len(rctx.routeParams.Keys) - 1 // index of last param in list
470		if nx >= 0 && rctx.routeParams.Keys[nx] == "*" && len(rctx.routeParams.Values) > nx {
471			routePath = "/" + rctx.routeParams.Values[nx]
472		}
473		return routePath
474	}
475	
476	// Recursively update data on child routers.
477	func (mx *Mux) updateSubRoutes(fn func(subMux *Mux)) {
478		for _, r := range mx.tree.routes() {
479			subMux, ok := r.SubRoutes.(*Mux)
480			if !ok {
481				continue
482			}
483			fn(subMux)
484		}
485	}
486	
487	// updateRouteHandler builds the single mux handler that is a chain of the middleware
488	// stack, as defined by calls to Use(), and the tree router (Mux) itself. After this
489	// point, no other middlewares can be registered on this Mux's stack. But you can still
490	// compose additional middlewares via Group()'s or using a chained middleware handler.
491	func (mx *Mux) updateRouteHandler() {
492		mx.handler = chain(mx.middlewares, http.HandlerFunc(mx.routeHTTP))
493	}
494	
495	// methodNotAllowedHandler is a helper function to respond with a 405,
496	// method not allowed. It sets the Allow header with the list of allowed
497	// methods for the route.
498	func methodNotAllowedHandler(methodsAllowed ...methodTyp) func(w http.ResponseWriter, r *http.Request) {
499		return func(w http.ResponseWriter, r *http.Request) {
500			for _, m := range methodsAllowed {
501				w.Header().Add("Allow", reverseMethodMap[m])
502			}
503			w.WriteHeader(405)
504			w.Write(nil)
505		}
506	}
